            aWandererE = aWandererE + ((((RotL64(aScatter, 51U) + RotL64(aOrbiterF, 53U)) + aOrbiterE) + RotL64(aCarry, 11U)) + aPhaseBWandererUpdateSaltA[(((31U - aIndex) + 24U)) & S_SALT1]);
            aWandererD = aWandererD ^ (((RotL64(aCross, 4U) + RotL64(aOrbiterB, 23U)) + aOrbiterH) + aPhaseBWandererUpdateSaltF[(((31U - aIndex) + 28U)) & S_SALT1]);
