            //
            aOrbiterF = ((aOrbiterF + aOrbiterD) + 0xDD0ECE7935AEEC60ULL) + aPhaseDOrbiterUpdateSaltE[((aIndex + 26U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterF) ^ 0xDA342959617CEF9BULL;
            aOrbiterK = RotL64((aOrbiterK * 0x1C8CA651B699DE21ULL), 39U);
