            //
            aOrbiterK = (aOrbiterK + aOrbiterB) + 0xCA50B36BA8A23A2FULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterK) ^ 0x6F21EEB55CF62A6EULL) ^ aPhaseDOrbiterUpdateSaltA[(((31U - aIndex) + 6U)) & S_SALT1];
